class Solution:
    def rob(self, nums: List[int]) -> int:
        def line(a):
            prev, cur = 0, 0
            for x in a:
                prev, cur = cur, max(cur, prev + x)
            return cur
        if len(nums) == 1:
            return nums[0]
        return max(line(nums[1:]), line(nums[:-1]))

