class Solution {
    int robLine(vector<int>& a, int l, int r) {
        int prev = 0, cur = 0;
        for (int i = l; i <= r; i++) {
            int nxt = max(cur, prev + a[i]);
            prev = cur; cur = nxt;
        }
        return cur;
    }
public:
    int rob(vector<int>& nums) {
        int n = nums.size();
        if (n == 1) return nums[0];
        return max(robLine(nums, 0, n - 2), robLine(nums, 1, n - 1));
    }
};

