static int robLine(int* a, int l, int r) {
    int prev = 0, cur = 0;
    for (int i = l; i <= r; i++) {
        int nxt = cur > prev + a[i] ? cur : prev + a[i];
        prev = cur; cur = nxt;
    }
    return cur;
}
int rob(int* nums, int n) {
    if (n == 1) return nums[0];
    int a = robLine(nums, 0, n - 2);
    int b = robLine(nums, 1, n - 1);
    return a > b ? a : b;
}
